        "url": "/algorithm/python/chapter20-%EC%B5%9C%EB%8C%80-%EC%8A%AC%EB%9D%BC%EC%9D%B4%EB%94%A9-%EC%9C%88%EB%8F%84%EC%9A%B0/",
